wsServer.on('connection', function (ws) {
  console.log('WebSocket server connected');

  // This function will handle incoming messages from your WebSocket server and forward them to the Minecraft server.  
  ws.on('message', function (message) {
    // This is where you'd implement logic to handle WebSocket messages.
