  'online-mode': false, // Work in offline mode for easier testing (don't do this in production)
  keepAlive: false,   // Disable keepalive for simplicity
  port: 25565,        // The default port for Minecraft
});

mcServer.on('login', function(client) {
  const remoteClient = mc.createClient({
    host: minecraftServer.host,
    port: minecraftServer.port,
    username: client.username
  });

  client.on('packet', function(data, meta) {
    if (remoteClient.state === mc.states.PLAY && meta.state === mc.states.PLAY) {
      remoteClient.write(meta.name, data);
    }
  });

  remoteClient.on('packet', function(data, meta) {
    if (client.state === mc.states.PLAY && meta.state === mc.states.PLAY) {
      client.write(meta.name, data);
    }
  });

  client.on('end', function() {
    remoteClient.end('End');
  });

  remoteClient.on('end', function() {
    client.end('End');
  });
});
